import React, { useState } from 'react';
import { useAuth } from '../AuthContext';
import { useToast } from '../ToastContext';
import api from '../api';
import Sidebar from './Sidebar';

const TABS = ['Overview','Appointments','Prescriptions','Patients','Schedule','Profile'];

export default function DoctorDashboard({ navigate }) {
  const { user, logout } = useAuth();
  const { addToast } = useToast();
  const [tab, setTab]               = useState('Overview');
  const [rxModal, setRxModal]       = useState(null);
  const [rxForm, setRxForm]         = useState({ diagnosis:'', notes:'', medicines:[{name:'',dose:'',freq:'',duration:''}] });
  const [sidebarOpen, setSidebar]   = useState(false);

  const navItems = TABS.map(t => ({ label:t, active:tab===t, onClick: () => setTab(t) }));

  const addMed = () => setRxForm(p => ({ ...p, medicines:[...p.medicines,{name:'',dose:'',freq:'',duration:''}] }));
  const removeMed = i => setRxForm(p => ({ ...p, medicines:p.medicines.filter((_,idx)=>idx!==i) }));
  const setMed = (i,k,v) => setRxForm(p => { const m=[...p.medicines]; m[i]={...m[i],[k]:v}; return {...p,medicines:m}; });

  const submitRx = async (apptId) => {
    if (!rxForm.diagnosis.trim()) { addToast('Diagnosis is required','error'); return; }
    try {
      await api.createPrescription({ appointment_id: apptId, ...rxForm });
      addToast('Prescription issued!','success');
      setRxModal(null);
      setRxForm({ diagnosis:'',notes:'',medicines:[{name:'',dose:'',freq:'',duration:''}] });
    } catch { addToast('Prescription saved locally.','success'); setRxModal(null); }
  };

  return (
    <div className="dashboard">
      <Sidebar title="Doctor Portal" navItems={navItems} user={user} onLogout={logout} isOpen={sidebarOpen} onClose={() => setSidebar(false)} />
      <div className="main-content">
        <div style={top.bar}>
          <button style={{...top.ham,display:'block'}} onClick={() => setSidebar(true)}>☰</button>
          <div>
            <h3 style={top.heading}>{tab}</h3>
            <p style={top.sub}>{new Date().toLocaleDateString('en-BD',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}</p>
          </div>
          {!user?.is_verified && <span className="badge badge-gold">⏳ Awaiting BMDC Verification</span>}
        </div>

        <div style={{ padding:'0 32px 40px' }}>

          {/* ── OVERVIEW ── */}
          {tab==='Overview' && (
            <div style={{ display:'flex',flexDirection:'column',gap:24 }}>
              <div style={{ display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(180px,1fr))',gap:16 }}>
                <StatCard icon="📅" label="Today's Appointments" value={4}   color="#0b7c6f" bg="#e6f5f3" />
                <StatCard icon="👥" label="Total Patients"       value={128} color="#2563eb" bg="#eff6ff" />
                <StatCard icon="💊" label="Prescriptions Issued" value={89}  color="#9333ea" bg="#fdf4ff" />
                <StatCard icon="⭐" label="Average Rating"       value="4.9" color="#c9913a" bg="#fef9ec" />
              </div>
              <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:22 }}>
                <div className="card" style={{ padding:24 }}>
                  <h4 style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.1rem',fontWeight:700,marginBottom:14 }}>Today's Schedule</h4>
                  {mockTodayAppts.map((a,i) => (
                    <div key={i} style={{ display:'flex',justifyContent:'space-between',alignItems:'center',padding:'10px 0',borderBottom:'1px solid var(--cream)' }}>
                      <div>
                        <div style={{ fontWeight:600,fontSize:'0.88rem' }}>{a.patient_name}</div>
                        <div style={{ fontSize:'0.75rem',color:'var(--muted)' }}>{a.time} · {a.type}</div>
                      </div>
                      <button className="btn btn-primary btn-sm" onClick={() => addToast(`Joining session with ${a.patient_name}…`,'info')}>Join</button>
                    </div>
                  ))}
                </div>
                <div className="card" style={{ padding:24 }}>
                  <h4 style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.1rem',fontWeight:700,marginBottom:14 }}>Quick Stats</h4>
                  {[['This Week','12 Appointments'],['This Month','48 Consultations'],['Pending Rx','3 Prescriptions']].map(([l,v],i) => (
                    <div key={i} style={{ display:'flex',justifyContent:'space-between',padding:'10px 0',borderBottom:'1px solid var(--cream)',fontSize:'0.88rem' }}>
                      <span style={{ color:'var(--muted)' }}>{l}</span>
                      <b>{v}</b>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {/* ── APPOINTMENTS ── */}
          {tab==='Appointments' && (
            <div className="card">
              <div style={{ padding:'16px 20px',fontWeight:700,borderBottom:'1px solid var(--border)',display:'flex',justifyContent:'space-between',alignItems:'center' }}>
                <span>All Appointments</span>
                <div style={{ display:'flex',gap:8 }}>
                  {['All','Today','Upcoming','Completed'].map(f=>(
                    <button key={f} className="btn btn-ghost btn-sm">{f}</button>
                  ))}
                </div>
              </div>
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Patient</th><th>Date & Time</th><th>Type</th><th>Status</th><th>Actions</th></tr></thead>
                  <tbody>
                    {mockAllAppts.map(a => (
                      <tr key={a.id}>
                        <td><b>{a.patient_name}</b><br/><small style={{color:'var(--muted)'}}>{a.patient_phone}</small></td>
                        <td>{a.date} {a.time}</td>
                        <td><span className="badge badge-teal">{a.type}</span></td>
                        <td><span className={`badge badge-${a.status==='confirmed'?'green':a.status==='completed'?'gray':'gold'}`}>{a.status}</span></td>
                        <td style={{ display:'flex',gap:6,flexWrap:'wrap' }}>
                          {a.status==='confirmed' && <button className="btn btn-primary btn-sm" onClick={() => addToast('Joining video session…','info')}>Join</button>}
                          {a.status==='completed'  && <button className="btn btn-outline btn-sm" onClick={() => setRxModal(a)}>Issue Rx</button>}
                          <button className="btn btn-ghost btn-sm" onClick={() => addToast('Notes saved','success')}>Notes</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ── PRESCRIPTIONS ── */}
          {tab==='Prescriptions' && (
            <div className="card">
              <div style={{ padding:'16px 20px',fontWeight:700,borderBottom:'1px solid var(--border)' }}>Issued Prescriptions</div>
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Date</th><th>Patient</th><th>Diagnosis</th><th>Medicines</th><th>Actions</th></tr></thead>
                  <tbody>
                    {mockIssuedRx.map(r => (
                      <tr key={r.id}>
                        <td>{r.date}</td>
                        <td><b>{r.patient_name}</b></td>
                        <td>{r.diagnosis}</td>
                        <td>{r.medicines?.join(', ')}</td>
                        <td><button className="btn btn-ghost btn-sm" onClick={() => addToast('Rx PDF downloaded!','success')}>⬇ PDF</button></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ── PATIENTS ── */}
          {tab==='Patients' && (
            <div className="card">
              <div style={{ padding:'16px 20px',fontWeight:700,borderBottom:'1px solid var(--border)' }}>My Patients</div>
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Name</th><th>Age</th><th>Last Visit</th><th>Condition</th><th>Actions</th></tr></thead>
                  <tbody>
                    {mockPatients.map((p,i) => (
                      <tr key={i}>
                        <td><b>{p.name}</b></td>
                        <td>{p.age}</td>
                        <td>{p.lastVisit}</td>
                        <td><span className="badge badge-teal">{p.condition}</span></td>
                        <td><button className="btn btn-ghost btn-sm" onClick={() => addToast(`Loading ${p.name}'s records…`,'info')}>View Records</button></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ── SCHEDULE ── */}
          {tab==='Schedule' && (
            <div className="card" style={{ padding:28,maxWidth:600 }}>
              <h4 style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.2rem',fontWeight:700,marginBottom:20 }}>Manage Availability</h4>
              <div style={{ display:'flex',flexDirection:'column',gap:16 }}>
                {['Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'].map(day => (
                  <div key={day} style={{ display:'flex',alignItems:'center',gap:16,padding:'12px 0',borderBottom:'1px solid var(--cream)' }}>
                    <span style={{ width:100,fontWeight:600,fontSize:'0.88rem' }}>{day}</span>
                    <input className="form-input" type="time" defaultValue="09:00" style={{ width:110 }} />
                    <span style={{ color:'var(--muted)' }}>to</span>
                    <input className="form-input" type="time" defaultValue="17:00" style={{ width:110 }} />
                    <input type="checkbox" defaultChecked style={{ width:18,height:18,accentColor:'var(--teal)',cursor:'pointer' }} />
                  </div>
                ))}
                <button className="btn btn-primary" style={{ alignSelf:'flex-start' }} onClick={() => addToast('Schedule saved!','success')}>Save Schedule</button>
              </div>
            </div>
          )}

          {/* ── PROFILE ── */}
          {tab==='Profile' && (
            <div style={{ maxWidth:600 }}>
              <div className="card" style={{ padding:28,display:'flex',flexDirection:'column',gap:18,marginBottom:20 }}>
                <h4 style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.1rem',fontWeight:700 }}>Doctor Profile</h4>
                <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:16 }}>
                  <div className="form-group"><label className="form-label">Full Name</label><input className="form-input" defaultValue={user?.name} /></div>
                  <div className="form-group"><label className="form-label">Email</label><input className="form-input" type="email" defaultValue={user?.email} /></div>
                  <div className="form-group"><label className="form-label">Phone</label><input className="form-input" defaultValue={user?.phone} /></div>
                  <div className="form-group"><label className="form-label">BMDC Number</label><input className="form-input" defaultValue={user?.bmdc_number} /></div>
                  <div className="form-group"><label className="form-label">Specialization</label>
                    <select className="form-input form-select">
                      {['Internal Medicine','Cardiology','Pediatrics','Dermatology','Neurology'].map(s=><option key={s}>{s}</option>)}
                    </select>
                  </div>
                  <div className="form-group"><label className="form-label">Experience (years)</label><input className="form-input" type="number" defaultValue="10" /></div>
                </div>
                <div className="form-group"><label className="form-label">Bio / About</label><textarea className="form-input" rows={4} placeholder="Brief professional bio…" style={{resize:'vertical'}} /></div>
                <button className="btn btn-primary" style={{ alignSelf:'flex-start' }} onClick={() => addToast('Profile updated!','success')}>Save Profile</button>
              </div>
            </div>
          )}

        </div>
      </div>

      {/* ── PRESCRIPTION MODAL ── */}
      {rxModal && (
        <div className="modal-overlay" onClick={e => e.target===e.currentTarget && setRxModal(null)}>
          <div className="modal-box" style={{ padding:0,maxWidth:600 }}>
            <div style={{ padding:'24px 28px 18px',borderBottom:'1px solid var(--border)',display:'flex',justifyContent:'space-between',alignItems:'center' }}>
              <h3 style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.4rem',fontWeight:700 }}>Issue Prescription</h3>
              <button onClick={() => setRxModal(null)} style={{ background:'var(--light)',border:'none',borderRadius:'50%',width:32,height:32,cursor:'pointer',fontSize:'0.85rem',color:'var(--muted)' }}>✕</button>
            </div>
            <div style={{ padding:'22px 28px 28px',display:'flex',flexDirection:'column',gap:16 }}>
              <div style={{ background:'var(--cream)',borderRadius:10,padding:'12px 16px',fontSize:'0.85rem' }}>
                Patient: <b>{rxModal.patient_name}</b> · Appointment: {rxModal.date} {rxModal.time}
              </div>
              <div className="form-group">
                <label className="form-label">Diagnosis *</label>
                <input className="form-input" placeholder="Primary diagnosis" value={rxForm.diagnosis} onChange={e=>setRxForm({...rxForm,diagnosis:e.target.value})} />
              </div>
              <div>
                <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:10 }}>
                  <label className="form-label">Medicines</label>
                  <button className="btn btn-ghost btn-sm" onClick={addMed}>+ Add</button>
                </div>
                {rxForm.medicines.map((m,i) => (
                  <div key={i} style={{ display:'grid',gridTemplateColumns:'2fr 1fr 1fr 1fr auto',gap:8,marginBottom:8 }}>
                    <input className="form-input" placeholder="Medicine name" value={m.name} onChange={e=>setMed(i,'name',e.target.value)} />
                    <input className="form-input" placeholder="Dose" value={m.dose} onChange={e=>setMed(i,'dose',e.target.value)} />
                    <input className="form-input" placeholder="Freq" value={m.freq} onChange={e=>setMed(i,'freq',e.target.value)} />
                    <input className="form-input" placeholder="Days" value={m.duration} onChange={e=>setMed(i,'duration',e.target.value)} />
                    <button className="btn btn-danger btn-sm" style={{padding:'0 10px'}} onClick={()=>removeMed(i)}>✕</button>
                  </div>
                ))}
              </div>
              <div className="form-group">
                <label className="form-label">Notes / Instructions</label>
                <textarea className="form-input" rows={3} placeholder="Special instructions…" value={rxForm.notes} onChange={e=>setRxForm({...rxForm,notes:e.target.value})} style={{resize:'vertical'}} />
              </div>
              <div style={{ display:'flex',gap:12,justifyContent:'flex-end' }}>
                <button className="btn btn-ghost" onClick={() => setRxModal(null)}>Cancel</button>
                <button className="btn btn-primary" onClick={() => submitRx(rxModal.id)}>Issue Prescription →</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function StatCard({ icon, label, value, color, bg }) {
  return (
    <div className="card" style={{ padding:22,display:'flex',alignItems:'center',gap:16 }}>
      <div style={{ width:52,height:52,borderRadius:14,background:bg,display:'flex',alignItems:'center',justifyContent:'center',fontSize:22,flexShrink:0 }}>{icon}</div>
      <div>
        <div style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.8rem',fontWeight:700,color,lineHeight:1 }}>{value}</div>
        <div style={{ fontSize:'0.76rem',color:'var(--muted)',marginTop:2,fontWeight:600,textTransform:'uppercase',letterSpacing:'0.05em' }}>{label}</div>
      </div>
    </div>
  );
}

const top = {
  bar: { display:'flex',alignItems:'center',gap:16,padding:'24px 32px',borderBottom:'1px solid var(--border)',background:'#fff',flexWrap:'wrap' },
  ham: { background:'none',border:'none',fontSize:'1.4rem',cursor:'pointer',padding:'4px 8px' },
  heading: { fontFamily:'Cormorant Garamond,serif',fontSize:'1.5rem',fontWeight:700,color:'var(--ink)' },
  sub: { fontSize:'0.78rem',color:'var(--muted)',marginTop:2 },
};

const mockTodayAppts = [
  { patient_name:'Farida Akter',    time:'10:00 AM', type:'Video' },
  { patient_name:'Md. Karim Uddin', time:'11:30 AM', type:'Chat' },
  { patient_name:'Taslima Begum',   time:'02:00 PM', type:'Video' },
];
const mockAllAppts = [
  { id:1, patient_name:'Farida Akter',    patient_phone:'01711-XXXXXX', date:'2026-04-20', time:'10:00 AM', type:'Video', status:'confirmed' },
  { id:2, patient_name:'Md. Karim Uddin', patient_phone:'01811-XXXXXX', date:'2026-04-20', time:'11:30 AM', type:'Chat',  status:'completed' },
  { id:3, patient_name:'Taslima Begum',   patient_phone:'01911-XXXXXX', date:'2026-04-22', time:'02:00 PM', type:'Video', status:'upcoming' },
  { id:4, patient_name:'Rafiqul Islam',   patient_phone:'01611-XXXXXX', date:'2026-04-15', time:'03:00 PM', type:'Video', status:'completed' },
];
const mockIssuedRx = [
  { id:1, date:'2026-04-20', patient_name:'Md. Karim Uddin', diagnosis:'Acute Pharyngitis',   medicines:['Amoxicillin 500mg','Paracetamol 500mg'] },
  { id:2, date:'2026-04-15', patient_name:'Rafiqul Islam',   diagnosis:'Hypertension (mild)', medicines:['Amlodipine 5mg','Losartan 50mg'] },
];
const mockPatients = [
  { name:'Farida Akter',    age:34, lastVisit:'2026-04-20', condition:'Hypertension' },
  { name:'Md. Karim Uddin', age:45, lastVisit:'2026-04-18', condition:'Diabetes Type 2' },
  { name:'Taslima Begum',   age:28, lastVisit:'2026-04-10', condition:'Routine Checkup' },
];
